《算法设计与分析》一书中回溯法习题求解 书写结构：解空间和解结构，剪枝策略，示例，代码，时间复杂度分析 5-1子集和问题 1. 解空间和解结构类似于0-1背包问题，对于S大小为n的子集和问题，解空间是由长度为n的0-1向量组成，解的结构为子集树，如对于上述示例的解，解空间即为(1,1,1,0,0,0) 2. 剪枝策略注意到题目说S是正整数的集合，c是正整数，故深搜的过程一定使得子集和增加或不变。 考虑在某节点处向下搜索的过程，设当前层数为k（即当前考虑是否加入数S[k]到子集中） 约束函数：维护变量cw表示当前子集和，若cw+S[k]&gt;c，则剪去左子树 限界函数：计算变量rw表示剩余的整数之和(S[k+1:n-1]之和)，若cw+rw&lt;c，即将之后所有整数加入子集也无法得到解，故减去右子树 对于本题而言，如果只要一个可行解的话，可以在搜索每个节点的时候，在考虑完是否加入数S[k]之后，判断S[k]是否等于c，若等于，则无需再搜索了 3. 示例太多了不太好画，减少点数据量： 123 102 2 6 4. 代码这里就没弄文件读写了（可以直接粘贴下面的输入测试啦） 输入1： 125 102 2 6 5 4 输入2： 125 102 11 12 5 4 得到一个解： 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556#include &lt;iostream&gt;#include &lt;windows.h&gt;using namespace std;const int N=100010;int S[N],res[N];int n,c;int num=0;//解的数量void dispsolution(int res[])&#123; cout&lt;&lt;&quot;第&quot;&lt;&lt;num++&lt;&lt;&quot;个解&quot;&lt;&lt;endl; for(int i=1;i&lt;=n;i++) &#123; if(res[i]) cout&lt;&lt;S[i]&lt;&lt;&quot; &quot;; &#125; cout&lt;&lt;endl;&#125;void dfs(int cw,int rw,int res[],int level)&#123; if(level&gt;n)//到达叶节点了 &#123; if(cw==c)//找到可行解 &#123; for(int i=1;i&lt;=n;i++) &#123; if(res[i]) cout&lt;&lt;S[i]&lt;&lt;&quot; &quot;; &#125; exit(0);//直接结束程序(会不会有点暴力) &#125; &#125;else&#123; if(cw+S[level]&lt;=c)//考虑是否进入左子树 &#123; res[level]=1; dfs(cw+S[level],rw-S[level],res,level+1); &#125; rw=rw-S[level];//计算剩余整数之和(剩余整数不包括当前整数) //这里和博客不太一样(他rw算的是包括当前的整数的) if(cw+rw&gt;=c)//考虑是否进入右子树 &#123; res[level]=0; dfs(cw,rw,res,level+1); &#125; &#125;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;c; int rw=0;//为了方便计算rw,首先计算所有整数的和 for(int i=1;i&lt;=n;i++)//为了方便,从下标1开始 &#123; cin&gt;&gt;S[i]; rw=rw+S[i]; &#125; dfs(0,rw,res,1);//cw=1,res存储解,从第一层开始 if(num==0) cout&lt;&lt;&quot;No Solution!&quot;&lt;&lt;endl; return 0;&#125; 得到所有解： 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849#include &lt;iostream&gt;using namespace std;const int N=100010;int S[N],res[N];int n,c;int num=0;//解的数量void dispsolution(int res[])&#123; cout&lt;&lt;&quot;第&quot;&lt;&lt;num++&lt;&lt;&quot;个解&quot;&lt;&lt;endl; for(int i=1;i&lt;=n;i++) &#123; if(res[i]) cout&lt;&lt;S[i]&lt;&lt;&quot; &quot;; &#125; cout&lt;&lt;endl;&#125;void dfs(int cw,int rw,int res[],int level)&#123; if(level&gt;n)//到达叶节点了 &#123; if(cw==c) dispsolution(res);//找到可行解 &#125;else&#123; if(cw+S[level]&lt;=c)//考虑是否进入左子树 &#123; res[level]=1; dfs(cw+S[level],rw-S[level],res,level+1); &#125; rw=rw-S[level];//计算剩余整数之和(剩余整数不包括当前整数) //这里和博客不太一样(他rw算的是包括当前的整数的) if(cw+rw&gt;=c)//考虑是否进入右子树 &#123; res[level]=0; dfs(cw,rw,res,level+1); &#125; &#125;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;c; int rw=0;//为了方便计算rw,首先计算所有整数的和 for(int i=1;i&lt;=n;i++)//为了方便,从下标1开始 &#123; cin&gt;&gt;S[i]; rw=rw+S[i]; &#125; dfs(0,rw,res,1);//cw=1,res存储解,从第一层开始 if(num==0) cout&lt;&lt;&quot;No Solution!&quot;&lt;&lt;endl; return 0;&#125; 5. 时间复杂度分析考虑最坏情况下时间复杂度，每个节点都进行搜索，处理每个节点所需的时间均为$O(1)$，一共有1+2+4+8+…+2^n^ =$O(2^{n+1})$个节点，故时间复杂度为$O(2^{n+1})$ 参考：https://blog.csdn.net/gl620321/article/details/108801724 5-2 最小长度电路板排列问题 1. 解空间和解结构类似于旅行商问题，对于n个电路板的最小电路板排列问题，其解空间为n个数的全排列，解结构为排列树 2. 剪枝策略维护变量bestd表示当前的最小长度，假设此时选择第i个位置上的电路板，考虑选择第j个电路板(j&gt;=i，因为i前面的已经选择好了)作为该位置上的排列，此时利用已经选择好的第1~第i个位置上的电路板（第i个位置刚刚选择好的）来计算连接块的最大长度，若该长度小于当前最优解，则继续进行下面位置的选择，否则第i个位置上不能选择第j个电路板，剪去该子树 3. 示例示例数据量太大，减少点 123454 41 1 1 11 1 0 10 0 0 10 1 1 0 4个电路板，L1={1,2},L2={1,2,4},L3={1,4},L4={1,2,3} 类似于下面的画法（排列树太多了，只画了一个子树）： 最后的结果： 4. 代码输入文件 input.txt: 1234567898 51 1 1 1 10 1 0 1 00 1 1 1 01 0 1 1 01 0 1 0 01 1 0 1 00 0 0 0 10 1 0 0 1 输入含义 L1={1,4,5,6},L2={1,2,3,6,8},L3={1,3,4,5},L4={1,2,3,4,6},L5={1,7,8} 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980818283#include &lt;iostream&gt;#include&lt;fstream&gt;#include &lt;vector&gt;using namespace std;int n, m;int bestx[10];// 这是最终的最优解排列顺序int B[10][10];//电路板在连接块中的排列，是一个二维数组int x[10], low[10], high[10];// 分别是当前的排列、最左边电路板、最右边电路板int bestd=0;// 最优解int len(int ii) &#123;// 计算当前ii排列最小长度 for (int i = 1; i &lt;= m; i++) &#123; high[i] = 0; low[i] = n + 1;// 先初始化最左边和最右边的值， &#125; for (int i = 1; i &lt;= ii; i++)// 对于第i行 for (int k = 1; k &lt;= m; k++)// k列 if (B[x[i]][k] &gt; 0) &#123;// 如果第i个电路板在第k个连接块中， if (i &lt; low[k])//low[k]代表第K个连接块的最左边的值，如果i比它小，则更新左值 low[k] = i; if (i &gt; high[k]) high[k] = i;//如果比初始的右值大，则更新右值 &#125; int tmp = 0; for (int k = 1; k &lt;= m; k++) if (low[k] &lt;= n &amp;&amp; high[k] &gt; 0 &amp;&amp; tmp &lt; high[k] - low[k]) //若连接块的长度无法得到（前面两个bool表达式不满足，不计算该连接块的长度） tmp = high[k] - low[k];//计算每个连接块的举例 return tmp;&#125;void swap(int* x, int i, int j) &#123;// 交换i和j位置的值 int tmp; tmp = x[i]; x[i] = x[j]; x[j] = tmp;&#125;void backtrack(int i) &#123; if (i == n) &#123;// 如果到达末尾 int tmp = len(i);// 计算当前排列最小长度 if (tmp &lt; bestd) &#123; bestd = tmp; for (int j = 1; j &lt;= n; j++) bestx[j] = x[j]; &#125; // 如果比最优解还要好，则更新bestx[]排列； &#125; else &#123;// 若不是末尾； for (int j = i; j &lt;= n; j++) &#123; swap(x, i, j); int ld = len(i); if (ld &lt; bestd) backtrack(i + 1);// 则继续进入下一个数， swap(x, i, j); &#125; &#125;&#125;int arrangeBoards() &#123; bestd = n + 1;// 先假设一个很大的值 for (int i = 1; i &lt;= n; i++) x[i] = i;// 这里是最开始的排序； backtrack(1); return bestd;&#125;int main(void) &#123; ifstream ifs(&quot;input.txt&quot;);//文件输入流 ifs&gt;&gt;n; ifs&gt;&gt;m; vector&lt;int&gt; temp(m); for (int i = 1; i &lt;= n; i++) &#123; for (int j = 1; j &lt;= m; j++) &#123; ifs&gt;&gt;B[i][j] ;// 输入的电路板的二维数组排列 &#125; &#125; int minLen = arrangeBoards(); cout&lt;&lt;minLen&lt;&lt;endl; for (int i = 1; i &lt;= n; i++) cout&lt;&lt;bestx[i]&lt;&lt;&quot; &quot;; ifs.close(); return 0;&#125; 5. 时间复杂度分析对于最坏情况，每个节点都需要计算一次len，即序号运行len函数，而第i层节点运行len函数时间复杂度为$O(im)$，故最坏情况下所需时间为$T=O(m)(n-1)+O(2m)(n-1)(n-2)+…+O(nm)(n-1)!$，故最坏情况下时间复杂度为$O(mn!)$ 5-3 最小重量机器设计问题 题目两个要求，总价格不超过d，并且部件重量之和要最小 1. 解空间和解结构对于n个部件，m个供应商的最小重量机器设计问题，其解空间为长度为n的向量，向量的每一项为1~m的整数，对应的解结构为排列树（也不是那种TSP的排列树，不过也是排列啦，姑且称之为排列树） 2. 剪枝策略考虑第i个部件供应商的选择 约束函数：维护变量cp表示当前已经购得的部件的价格之和，假设考虑选择第j个供应商，若cp+c[i][j]&gt;d，则剪去以该节点为根节点的子树，无需再进行搜索 限界函数：维护变量cw表示当前已经购得的部件的重量之和，变量bestw表示当前最优解的重量之和，假设考虑选择第j个供应商，若cw+w[i][j]&gt;=bestw，则剪去该节点为根节点的子树，无需进行搜索 3. 示例对于题中示例画树： 4. 代码输入： 12345673 3 41 2 33 2 12 2 21 2 33 2 12 2 2 没实现文件读写了~ 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354#include&lt;bits/stdc++.h&gt;using namespace std;int n,m,d;//n个部件，m个供应商，总价格不超过dint c[999][999];//c[i][j]为从供应商j购买部件i所花费的价格；int w[999][999];//w[i][j]为......重量int cw=0,cp=0;//当前部件的重量 价格int bestw=999,bestp=999;//最优方案的重量，价格int x[999];//当前部件i从供应商j购买int bestx[999];//最优方案部件i从哪个供应商买void backtrack(int i)&#123; if(i&gt;=n)&#123;//到达最后一层 if(cp&lt;=d&amp;&amp;cw&lt;bestw)&#123;//如果价格没超过d，并且重量小于之前方案的bestw bestw=cw;//重量更新 bestp=cp;//价格更新 for(int k=0;k&lt;n;k++)&#123; bestx[k]=x[k];//部件的供应商进行更新 &#125; &#125; &#125; else&#123; //所有的方式都尝试了一遍，比较找到最优的重量 for(int j=0;j&lt;m;j++)&#123; x[i]=j;//当前部件i的供应商为j cw=cw+w[i][j]; cp=cp+c[i][j]; if(cw&lt;bestw&amp;&amp;cp&lt;=d)//如果这次的选择要比之前方案的更优 backtrack(i+1); //回溯 cw-=w[i][j]; cp-=c[i][j]; &#125; &#125;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;m&gt;&gt;d;//n个部件，m个供应商，总价格不超过d int i=0,j=0; for(i=0;i&lt;n;i++)&#123; for(j=0;j&lt;m;j++)&#123; cin&gt;&gt;c[i][j];//c[i][j]为从供应商j购买部件i所花费的价格； &#125; &#125; for(i=0;i&lt;n;i++)&#123; for(j=0;j&lt;m;j++)&#123; cin&gt;&gt;w[i][j];//w[i][j]为......重量 &#125; &#125; backtrack(0);//第i个部件 cout&lt;&lt;bestw&lt;&lt;endl;//最优方案的重量 for(int k=0;k&lt;n;k++) cout&lt;&lt;bestx[k]+1&lt;&lt;&quot; &quot;; //因为j从0开始，所以输出的时候加一个1；&#125; 5. 时间复杂度分析考虑最坏情况，对于每个非叶子节点，搜索所需时间为$O(m)$，对于每个叶子节点，搜索所需的时间为$O(1)$，故最坏情况下所需时间为$T=m*(m+m^2+…+m^{n-1})+m^n=O(m^n)$ 5-4 运动员最佳配对问题 输入： 1234567310 2 32 3 43 4 52 2 23 5 34 5 1 输出： 152 1. 解空间和解结构将问题转换为男运动员选女运动员的问题，故n个男、女运动员的运动员最佳匹配问题的解空间为n个数的全排列，对应的解结构为排列树 2. 剪枝策略考虑对第i个男运动员匹配女运动员的情况，其中变量Max存储当前最优解的竞赛优势，变量sum存储第1~i-1个已经匹配完成的男运动员的竞赛优势，计算第i~n个男运动员的最大可能的竞赛优势ctn，若cnt+sum&lt;Max，则剪去该节点及其子树 其中第j个男运动员的最大可能的竞赛优势为该男运动员与所有女运动员进行匹配所得竞赛优势中最大者，存储到maxsum数组中 3.示例 4.代码1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465#include &lt;bits/stdc++.h&gt;using namespace std;int n;int boy[21][21],girl[21][21]; //分别用于存放男、女运动员的竞赛优势int Max=INT_MIN; //Max代表男女双方竞赛优势的总和的最大值int sum=0; //sum为临时求和int data[21][21]; //data[i][]用于存放男运动员 i 配对后的双方竞赛优势int maxSum[21]; //记录每个男生匹配后可达到的最大双方竞赛优势int book[21]; //用于标记女运动员是否已匹配：book[0]未匹配；book[1]匹配void dfs(int t)&#123; if(t&gt;=n) //t到达n之后，代表全部标记访问了,得到了最大值 &#123; Max=max(Max,sum); return ; &#125; int ctn=0; //剪枝函数:之前t个已匹配好的男女运动员的sum与之后的 t-&gt;n-1 个男匹配女的最大值加起来与已经得到的Max比较，若前者&lt;=Max，剪枝 for(int i=t;i&lt;n;i++) //求t及t之后男生匹配女生的最大值的和 ctn+=maxSum[i];//若从第t组-&gt;第n组，当前搜索sum加上假设匹配后的最大值cxn，仍然小于Max ，就需要剪枝了，则Max为已经求得的最大值 if(sum+ctn&lt;Max) return ; for(int i=0;i&lt;n;i++) //若cxn&gt;=Max，要探索子树。从第t个男生开始匹配，找未匹配的女生 &#123; if(!book[i]) //第 i 个女生未匹配 &#123; book[i]=1; //第 t 个男生匹配女生i sum+=data[t][i]; //加上男生t与女生i的男女双方竞赛优势 dfs(t+1); //为第i+1个男生匹配 book[i]=0; //若第 t 个男生匹配女生i得到的sum不大于Max，则回溯 sum-=data[t][i]; &#125; &#125;&#125;int main()&#123; cin&gt;&gt;n; for(int i=0;i&lt;n;i++) //输入男运动员的竞赛优势 &#123; for(int j=0;j&lt;n;j++) cin&gt;&gt;boy[i][j]; &#125; for(int i=0;i&lt;n;i++) //输入女运动员的竞赛优势 &#123; for(int j=0;j&lt;n;j++) cin&gt;&gt;girl[i][j]; &#125; for(int i=0;i&lt;n;i++) &#123; for(int j=0;j&lt;n;j++) &#123; //对每个男生都求男女双方竞赛优势，则能得到i*j种结果（涵盖了P[i][j]*Q[j][i]与Q[i][j]*P[j][i]） data[i][j]=boy[i][j]*girl[j][i]; maxSum[i]=max(maxSum[i],data[i][j]); //记录每个男生匹配后可达到的最大双方竞赛优势，用于后面的剪枝 &#125; &#125; dfs(0); cout&lt;&lt;Max&lt;&lt;endl; return 0;&#125; 5.时间复杂度分析考虑最坏情况，每个节点都需要搜索，对于非叶子节点，其需要时间为$O(n)$，对于叶子节点，其所需时间为$O(1)$，故所需时间为$T=n(n+n(n-1)+…+n!)+n!=O(n*n!)$ 5-5 无分隔符字典问题 1. 解空间和解结构由S为$L_k$子集可知n个符号，长度为k的无分隔符字典问题的解空间为长度为$n^k$的向量，其中向量每一项为0或1，表示$L_k$中某一项是否在S中，解结构为子集树 2. 剪枝策略首先将$L_k$中所有字字符串放入数组L中，考虑是否放入下标为i的字符串： 约束函数：若该字符串与当前S集合中的任意字符串按照题目所给方式进行拼接，结果均不在S集合中，且不为该字符串本身，则考虑将其放入，搜索其左子树，否则剪去该节点的左子树 限界函数：考虑不放入该字符串，若将i+1~$n^k$的字符串均放入，若n^k^-i+S.size&lt;best，则无需搜索其右子树，剪去该节点的右子树 3. 示例假设$\sum=(a,b),L_k=\{aa,ab,ba,bb\}$,则$L_k$的一个最大无分隔符字典为$\{aa,bb\}$ 4. 代码#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;vector&gt;#include &lt;set&gt;using namespace std;int *ak;int lk;int n, k;int best = 0; //最大无分隔符字典元素个数vector&lt;int&gt; L; //将所有的长度为k的数字字符串存到集合L中set&lt;int&gt; S; //当前字典中的字符串存储在集合s中//将下标为L[]中下标为i的字符串存入集合svoid insert(int i)&#123; S.insert(L[i]);&#125;//将下标为L[]中下标为i的字符串存入集合svoid erase(int i)&#123; S.erase(L[i]);&#125;//将ak[]中起点为i，长度为k数字串转换为十进制数字int digi(int i)&#123; int x = 0; for(int j=0; j&lt;k; j++) &#123; x *= 10; x += ak[j]; &#125; return x;&#125;//判断字符串a和第b个字符串是否互不为前缀bool pref(int a, int b)&#123; int bb =b;//这里用bb只是因为原代码不太对,我直接改了 int x = a; int y = bb/10;//去掉最后一位，得到高k-1位(因为验证的时候这位是肯定要剔除的 //按理说x也要剔除最高位，但是后面的循环不会碰到最高位，所以这里没剔除了 for(int i=0; i&lt;k-1; i++) //ak[0, k-2]存放x的低k-1位，ak[k-1, k-1 + (k-2)]存放y &#123; ak[k-i-2] = x % 10; x /= 10; ak[2*k-i-3] = y % 10; y /= 10; &#125; for(int i=0; i&lt;k-1; i++) //相当于依次判断a2a3..akb1, a3a4..b1b2, akb1..bk-1是否已存在于S中，本程序中下标从0开始 if(S.count(digi(i)) &gt; 0||digi(i)==bb) //如果已存在于S中 return true; x = bb; y = a/10; for(int i=0; i&lt;k-1; i++)//先放b再放a &#123; ak[k-i-2] = x % 10; x /= 10; ak[2*k-i-3] = y % 10; y /= 10; &#125; for(int i=0; i&lt;k-1; i++) if(S.count(digi(i)) &gt; 0||digi(i)==bb) return true; return false;&#125;//判断当前下标为b的字符串是否可以加入字典//将字符串a1a2..ak看作k位十进制数bool oka(int b)&#123; int bb = L[b]; set&lt;int&gt;::iterator it; //定义迭代器 it = S.begin(); while(it != S.end()) &#123; int a = *it; if(pref(a, bb)) //如果a,b其中一个是另一个的前缀 return false; it++; &#125; return true;&#125;//得到总元素个数为n，长度为m的全排列void Perm(int list[], int dep, int m, int n)&#123; if(dep&gt;m) &#123; int x = 0; for(int i=1; i&lt;=m; i++) x = x*10 + list[i]; //转换为十进制数字 L.push_back(x); //将所有的数字字符串存到集合L中 &#125; else for(int j=1;j&lt;=n;j++) &#123; swap(list[dep], list[j]); Perm(list, dep+1, m, n); swap(list[dep], list[j]); &#125;&#125;void backtrack(int dep)&#123; if(dep &gt;= lk) &#123; if(S.size() &gt; best) best = S.size(); return; &#125; if(oka(dep)) &#123; insert(dep); backtrack(dep+1); erase(dep); &#125; if(lk-dep+S.size()&gt;best) backtrack(dep+1);&#125;int main()&#123; ifstream fin(&quot;input.txt&quot;); cout &lt;&lt; &quot;输入正整数n：&quot;; fin &gt;&gt; n; cout &lt;&lt; n; cout &lt;&lt; &quot;
输入正整数k：&quot;; fin &gt;&gt; k; cout &lt;&lt; k; ak = new int[2*k]; lk = n; for(int i=1; i&lt;k; i++) //k个字符中，每一个字符都有n种选择，n^k表示所有由k个字符组成的字符串种数 lk *= n; lk--; int *x = new int[n+1]; for(int i=1; i&lt;=n; i++) x[i] = i; Perm(x, 1, k, n); //将长度为k的全排列存入集合L中 backtrack(0); cout &lt;&lt; &quot;
最大无分隔符字典元素个数为：&quot; &lt;&lt; best; cout &lt;&lt; endl; cout &lt;&lt; endl; fin.close(); return 0;&#125; 5. 时间复杂度考虑最坏情况，对于n个字符，长度为k的问题，对于每个非叶子节点的左子节点，搜索需要耗费时间为$O(n^kk)$，对于右子节点搜索需要的时间为$O(1)$，对于叶节点需要时间$O(1)$，故耗费的时间$T=O(2^{n^k-1}n^k*k)$ 5-6 无合集问题 大概的思路是从1开始每个数都尝试放入n个子集的每个子集，然后用题目给的条件x+y不属于S进行剪枝 1. 解空间和解结构从1开始尝试放入每个子集中，对于子集为n的无合集问题，其解空间为长度为k的向量，向量的每一项为1~n，表示对应下标的数分配到的子集，其中k为本题所求，以n=3为例，解结构如下： 2. 剪枝策略据题意，若数i无法分配到集合j(不满足和不在集合的条件)，则该节点的第j个分支无需遍历，剪去该分支 3. 示例 4. 代码定义存储当前解的数组a[N][N],其中a[n][0]表示第n个子集的元素个数a[n][1]到a[n][a[n][0]]为这个子集的所有元素。定义n。设置初始的结果ans为1(最后要减1，所以初始值其实是0)，定义最优值为best，定义最优解为e[N][N]，其中的结构和a[N][N]一样,以及定义判定数组h[N][N]，h[i][j]表示第i个子集中是否有j这个元素。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051#include &lt;bits/stdc++.h&gt;using namespace std;const int N = 110;int a[N][N], n, ans = 1, best, e[N][N];bool h[N][N];void dfs(int level)&#123; //判断当前ans中的数是否能插入第level个子集 if(level == n)&#123; //n个子集的下标是0到n-1,所以当level等于n时表示当前ans不能插入所有子集 if(ans &lt;= best) return; //如果当前ans不如当前最优值best，就返回 best = ans; //如果比最优值好，更新最优值和最优解 for(int i = 0; i &lt; n; i ++)&#123; for(int j = 0; j &lt;= a[i][0]; j ++) e[i][j] = a[i][j]; &#125; return; &#125; else&#123; //判断ans能否插入第level个子集 bool flag = true; for(int i = 1; i &lt;= a[level][0]; i ++)&#123;//遍历子集 //如果ans减当前元素在子集中且这个元素不是它本身,flag就为false,表示ans不能插入这个子集 if(h[level][ans - a[level][i]] &amp;&amp; ans - a[level][i] != a[level][i]) flag = false; &#125; if(!flag) dfs(level + 1); //不能插入，判断ans能不能插入第level+1个子集 else&#123; //可以插入，分两种情况，一种是插入，一种是不插入此子集 //插入的情况 a[level][++ a[level][0]] = ans; //第i个子集个数加一，把元素记入子集 h[level][ans ++] = true; //把此元素标记为在此子集中 dfs(0); //判断下一个数是否能插入第0个子集 //回溯到不插入的情况，把子集个数减1，再把当前元素标记为不在此子集中 -- a[level][0]; h[level][-- ans] = false; dfs(level + 1); //判断这个数是否能插入下一个子集 &#125; &#125;&#125;int main()&#123; cin &gt;&gt; n; dfs(0); cout &lt;&lt; --best &lt;&lt; endl; //记录的是最优值加一，这里减去一并输出 for(int i = 0; i &lt; n; i ++)&#123; for(int j = 1; j &lt;= e[i][0]; j ++) printf(&quot;%d &quot;, e[i][j]); //输出最优解 puts(&quot;&quot;); &#125; return 0;&#125; 参考：无和集问题 - AcWing 5. 时间复杂度考虑最坏情况，对于非叶子节点，假设其位于第i层，则时间消耗为$O(i)$，对于非叶子节点，其时间消耗为$O(1)$,本题时间消耗还与树的层数有关，而层数又是要求的。。。，需要一些推导来得到一个上界吧~ 5-7 n色方柱问题 为了提高效率，用图论的知识简化了题目（我没怎么看懂为啥这样简化的），谢谢有被恶心到 有点难懂，我觉得不会考。。。，理解一下代码吧 代码input.txt: 1234564RGBY0 2 1 3 0 03 0 2 1 0 12 1 0 2 1 31 3 3 0 2 2 #include&lt;iostream&gt;#include&lt;fstream&gt;#include&lt;algorithm&gt;using namespace std;const int MAX = 50;int board[MAX][6]; //存储n个立方体各面的颜色int solu[MAX][6]; //存储解int n; //立方体个数、颜色种数int ans = 0; //解的个数int used[MAX];char color[MAX];//找到一个解后，输出void out(int edge[])&#123; int i, j, k, a, b, c, d; for(i=0; i&lt;2; i++) //2个子图 &#123; for(j=0; j&lt;n; j++) used[j] = 0; do&#123; j = 0; d = c = -1; while(j&lt;n &amp;&amp; used[j]&gt;0) //找下一条未用的边 j++; if(j &lt; n) do&#123; a = board[j][edge[i*n+j]*2]; b = board[j][edge[i*n+j]*2+1]; if(b == d) //如果上一条边的终点与b相同，说明b为始点，交换，保证a为始点 swap(a, b); //保证有向边的始点对应于前面和左面，终点对应于背面和右面 solu[j][i*2] = a; solu[j][i*2+1] = b; used[j] = 1; if(c&lt;0) //开始顶点 c = a; d = b; for(k=0; k&lt;n; k++) //找下一个立方体 if(used[k]==0 &amp;&amp; (board[k][edge[i*n+k]*2]==b || board[k][edge[i*n+k]*2+1]==b)) j = k; &#125;while(b != c); //找了一圈，回到起点 &#125;while(j&lt;n); //所有立方体都找遍 &#125; for(j=0; j&lt;n; j++) //立方体的顶面和底面的颜色 &#123; k = 3 - edge[j] - edge[j+n]; a = board[j][k*2]; b = board[j][k*2+1]; solu[j][4] = a; solu[j][5] = b; &#125; for(i=0; i&lt;n; i++) &#123; for(j=0; j&lt;6; j++) cout &lt;&lt; color[solu[i][j]] &lt;&lt; &quot; &quot;; cout &lt;&lt; endl; &#125;&#125;void search()&#123; int i, t, cube; bool ok, newg, over; int *vert = new int[n]; //记录子图中每个顶点的度，应均为2 int *edge = new int[n*2]; //记录每个立方体中边被选用的条数，每个立方体只有3条边，有两个子图要选用 for(i=0; i&lt;n; i++) vert[i] = 0; t = -1; newg = true; while(t &gt; -2) &#123; t++; cube = t % n; //每个立方体找2次，得到真实的立方体编号，也是子图中边的编号 if(newg) //如果没有边被选入子图 edge[t] = -1; over = false; //是否结束，即两个子图构建完成 ok = false; //标记边是否已用过，两个子图不应有公共边 while(!ok &amp;&amp; !over) &#123; edge[t]++; //边被选用加入子图，使用次数增加 if(edge[t]&gt;2) //在立方体每对相对面的顶点连一条边，每个立方体只有3条边 over = true; else ok = (t&lt;n || edge[t]!=edge[cube]); //是否已用过 &#125; if(!over) &#123; //检测边的两个顶点的度 if(++vert[board[cube][edge[t]*2]] &gt; 2+t/2*2) //如果是第一个子图，顶点度不能超过2 ok = false; //如果是第二个子图，加上第一个子图，顶点度不能超过4 if(++vert[board[cube][edge[t]*2+1]] &gt; 2+t/2*2) ok = false; if(t%n == n-1 &amp;&amp; ok) //如果一个或两个子图已构建完成 for(i=0; i&lt;n; i++) if(vert[i] &gt; 2+t/n*2) ok = false; if(ok) &#123; if(t == n*2-1) //找到解 &#123; ans++; out(edge); return; &#125; else newg = true; &#125; else //取下一条边 &#123; --vert[board[cube][edge[t]*2]]; //边的两个顶点 --vert[board[cube][edge[t]*2+1]]; t--; newg = false; &#125; &#125; else //回溯 &#123; t--; if(t &gt; -1) &#123; cube = t % n; --vert[board[cube][edge[t]*2]]; --vert[board[cube][edge[t]*2]]; &#125; t--; newg = false; &#125; &#125;&#125;int main()&#123; ifstream fin(&quot;input.txt&quot;); cout &lt;&lt; &quot;输入立方体个数：&quot;; fin &gt;&gt; n; cout &lt;&lt; n; cout &lt;&lt; &quot;
