3839404142434445#include&lt;stdio.h&gt;#define N 10int m,n; //分别为行、列int count=0;int a[N][N]=&#123;0&#125;;int row[N][N]=&#123;0&#125;;//row[i][j]=1表示第i行已经使用了形状jint col[N][N]=&#123;0&#125;;//col[j][i]=1表示第i列已经使用了形状jvoid backtrack(int t)//t表示正在填充的矩阵的一个小格子,格子范围为0~m*n-1//如第一行就是0 1 2 3 4...&#123; int i,j; int x,y; //分别为行、列（坐标） if(t==m*n)//如果排完了,说明得到了一种可行解 &#123; count++; return; &#125; //否则继续排列 x=t/n; //行坐标 y=t%n; //列坐标 for(i=1;i&lt;=n;i++)//对每种形状都进行尝试 &#123; if(row[x][i]==0&amp;&amp;col[i][y]==0) &#123; row[x][i]=1; col[i][y]=1; a[x][y]=i; backtrack(t+1); row[x][i]=0;//回溯 col[i][y]=0; a[x][y]=0; &#125; &#125;&#125;int main()&#123; scanf(&quot;%d%d&quot;,&amp;m,&amp;n); backtrack(0); printf(&quot;count=%d
&quot;,count); return 0;&#125; 5. 时间复杂度考虑最坏情况，对于叶子节点，其时间消耗为$O(1)$，对于非叶子节点其时间消耗为$O(n)$，对于n种宝石，排成n行m列的拉丁矩阵问题，时间消耗为$T=O(n^{mn})$ 5-10 排列宝石问题 这道题是类似于5-9的(直接在5-9上面改的几行)，说一下思路吧：类似于对待不同宝石类型要求每行每列都不重复，引入数组color_row和数组color_col，其大致结构和含义与row和col类似，用于记录该行或者该列是否已经使用过该种颜色的宝石，还引入used数组用于满足题中的每种宝石n颗且不同色（避免一种宝石的一种颜色使用了多次），其中used[i][j]=1表示类型i的宝石的第j种颜色已用。 与5-9对比，排列树可选的分支大大增加了，不过剪去的分支也比较多，时间复杂度往上蹭 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455#include&lt;bits/stdc++.h&gt;#define N 10using namespace std;int n; //分别为行、列int res=0;int row[N][N]=&#123;0&#125;;//row[i][j]=1表示第i行已经使用了形状jint col[N][N]=&#123;0&#125;;//col[j][i]=1表示第i列已经使用了形状jint color_row[N][N]=&#123;0&#125;;int color_col[N][N]=&#123;0&#125;;int used[N][N]=&#123;0&#125;;//used[i][j]=1表示类型i的第j种颜色已用void backtrack(int t)//t表示正在填充的矩阵的一个小格子,格子范围为0~m*n-1//如第一行就是0 1 2 3 4...&#123; int i,j; int x,y; //分别为行、列（坐标） if(t==n*n)//如果排完了,说明得到了一种可行解 &#123; res++; return; &#125; //否则继续排列 x=t/n; //行坐标 y=t%n; //列坐标 for(i=1;i&lt;=n;i++)//对每种形状都进行尝试 &#123; for(j=1;j&lt;=n;j++)&#123;//j为颜色 if(!row[x][i]&amp;&amp;!col[i][y]&amp;&amp;!color_row[x][j]&amp;&amp;!color_col[j][y]&amp;&amp;!used[i][j]) &#123; row[x][i]=1; col[i][y]=1; color_row[x][j]=1; color_col[j][y]=1; used[i][j]=1; backtrack(t+1); row[x][i]=0; col[i][y]=0; color_row[x][j]=0; color_col[j][y]=0; used[i][j]=0; &#125; &#125; &#125;&#125;int main()&#123; scanf(&quot;%d&quot;,&amp;n); backtrack(0); printf(&quot;res=%d
&quot;,res); return 0;&#125; 5-11 重复拉丁矩阵问题 这题是类似于5-9的，我的代码一直没AC，参考了下答案的，思路是：第一行按照题意，由于对每行每种宝石数量的限制，且要求第一行最小字典序，所以是固定的，无需回溯，故从第二行开始进行搜索。答案遵照教材的排列树的写法，先初始化矩阵，然后再做swap操作，矩阵初始化情况如虚线上矩阵(示例为例)，在搜索的时候，只需要考虑每列宝石要求即可（因为初始化的原因，不需要考虑每行了），但是很奇怪的是，代码没有考虑第一列的情况了，即认为第一列也是固定的，但是我觉得不太对，比如虚线下面的一种也是可以的。 12345678910省略第0行、第0列1 1 2 2 3 3 31 &lt;1&gt; 2 2 3 3 32 1 1 2 3 3 32 1 2 1 3 3 3-------------1 1 2 2 3 3 3 3 3 3 2 2 1 1 3 3 3 1 2 2 1 3 3 2 1 3 1 2 input: 124 7 32 2 3 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899#include&lt;iostream&gt;#include&lt;fstream&gt;#include&lt;algorithm&gt;using namespace std;const int MAX = 50;int n, m, k;int times[MAX]; //每种宝石的重复次数int id[MAX]; //每个宝石的价值序号int board[MAX][MAX]; //宝石矩阵//考察当前列宝石数是否多于应出现的次数bool ok(int r, int c, int s)&#123; int k = board[r][s]; int i; if(s &gt; c) for(i=c; i&lt;s; i++) if(board[r][i] == k) //如果已经试过相同类型的宝石，这次就不再试了 return false; int count = 0; for(i=1; i&lt;r; i++) //考察当前列宝石数是否多于应出现的次数 if(board[i][c] == k) count++; if(count &gt;= times[k]) //times[k]表示种类为k的宝石应出现的次数 return false; else return true;&#125;double num = 0; //不同的宝石排列方案数//从上到下，从左到右递归搜索，即先行后列void backtrack(int r, int c)&#123; for(int i=c; i&lt;=n; i++) //列 if(ok(r, c, i)) &#123; swap(board[r][c], board[r][i]); if(c == n) //如果列考察完毕 &#123; if(r == m) //如果行考察完毕 &#123; num += 1; //cout &lt;&lt; num &lt;&lt; &quot; &quot;; return; &#125; else backtrack(r+1, 2); //考察下一行 &#125; else backtrack(r, c+1); //考察下一列 swap(board[r][c], board[r][i]); &#125;&#125;int main()&#123; ifstream fin(&quot;input.txt&quot;); cout &lt;&lt; &quot;
